    // Set headers to trigger a progressive download in the browser
    res.setHeader('Content-Type', 'application/pdf');
    res.setHeader('Content-Disposition', 'attachment; filename="large-report.pdf"');

    // Initialize document and define page size
    const doc = new PDFDocument({
        size: 'A4',
        bufferPages: false // Crucial: forces PDFKit to release memory as pages write
    });

    // Pipe the PDF write stream directly to the Express response stream
    doc.pipe(res);

    // Simulate reading from a database cursor stream
    const dbStream = getLargeDatasetCursor(); 

    dbStream.on('data', (row) => {
