        doc.text(`Record ID: ${row.id} - Name: ${row.name}`);
        doc.moveDown();
    });

    dbStream.on('end', () => {
        doc.end(); // Finalize the PDF and close the response
    });

    dbStream.on('error', (err) => {
        doc.destroy();
        res.status(500).end('Export failed');
    });
