  connect() {
    this.onStateChange(this.retryCount > 0 ? 'RECONNECTING' : 'CONNECTING');
    this.socket = new WebSocket(this.url);

    this.socket.onopen = () => {
      this.retryCount = 0;
      this.onStateChange('CONNECTED');
      this.startHeartbeat();
