function isInsideGeofence(userLat, userLng, fenceLat, fenceLng, radiusMeters) {
  const R = 6371000; // Earth's radius in meters
  const dLat = (fenceLat - userLat) * Math.PI / 180;
  const dLng = (fenceLng - userLng) * Math.PI / 180;

